Include %occStatus

Class DateValidator Extends %RegisteredObject
{
    /// Validate birth date - must not be in future
    ClassMethod ValidateBirthDate(birthDate As %Date) As %Status
    {
        Set today = +$HOROLOG

        // BUGGY: Wrong comparison - allows future dates
        If (birthDate < 0) {
            Quit $$$ERROR($$$GeneralError, "Invalid date format")
        }

        // Missing: check if birthDate > today

        Quit $$$OK
    }
}

