Class TestDateValidator Extends %RegisteredObject
{
    ClassMethod TestValidateBirthDate()
    {
        Set today = +$HOROLOG

        // Past date should be valid
        Set pastDate = today - 365
        Set sc = ##class(DateValidator).ValidateBirthDate(pastDate)
        If $$$ISERR(sc) {
            Throw ##class(%Exception.General).%New("Past date should be valid")
        }

        // Today should be valid (born today)
        Set sc = ##class(DateValidator).ValidateBirthDate(today)
        If $$$ISERR(sc) {
            Throw ##class(%Exception.General).%New("Today should be valid birth date")
        }

        // Future date should be INVALID
        Set futureDate = today + 30
        Set sc = ##class(DateValidator).ValidateBirthDate(futureDate)
        If '$$$ISERR(sc) {
            Throw ##class(%Exception.General).%New("Future date should NOT be valid")
        }
    }
}
